import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.BYehg5q7.js";const d=JSON.parse('{"title":"Batch Import","description":"","frontmatter":{},"headers":[],"relativePath":"guide/batch-import.md","filePath":"guide/batch-import.md","lastUpdated":1772287587000}'),i={name:"guide/batch-import.md"};function s(l,e,n,h,c,p){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="batch-import" tabindex="-1">Batch Import <a class="header-anchor" href="#batch-import" aria-label="Permalink to &quot;Batch Import&quot;">​</a></h1><p>If you have multiple lab reports to import at once — for example, several years of annual blood work — you can drop them all at the same time instead of importing one by one.</p><h2 id="how-batch-import-works" tabindex="-1">How Batch Import Works <a class="header-anchor" href="#how-batch-import-works" aria-label="Permalink to &quot;How Batch Import Works&quot;">​</a></h2><ol><li>Select multiple PDF files (hold Shift or Ctrl/Cmd while clicking to select several)</li><li>Drag them all onto the drop zone at the same time</li><li>getbased processes them <strong>one file at a time</strong>, in order</li></ol><p>For each file, you go through the normal import preview — review matched markers, then confirm or skip. The app shows you which file you&#39;re on (e.g., &quot;File 2 of 5&quot;) so you always know your progress.</p><h2 id="confirm-or-skip-per-file" tabindex="-1">Confirm or Skip Per File <a class="header-anchor" href="#confirm-or-skip-per-file" aria-label="Permalink to &quot;Confirm or Skip Per File&quot;">​</a></h2><p>You have full control over each import:</p><ul><li><strong>Confirm</strong> — save the results from this file and move to the next</li><li><strong>Skip</strong> — discard this file&#39;s results and move to the next without saving</li></ul><p>This is useful if one report in the batch has formatting issues or belongs to someone else.</p><h2 id="auto-retry" tabindex="-1">Auto-Retry <a class="header-anchor" href="#auto-retry" aria-label="Permalink to &quot;Auto-Retry&quot;">​</a></h2><p>If the AI fails to extract data from a file (e.g., due to a network glitch or timeout), getbased automatically retries that file once before offering the option to skip. This reduces manual intervention for transient errors.</p><h2 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h2><p>The dashboard only refreshes once at the end of a batch import, not after each individual file. This makes large batches significantly faster and avoids unnecessary re-rendering between files.</p><h2 id="summary-at-the-end" tabindex="-1">Summary at the End <a class="header-anchor" href="#summary-at-the-end" aria-label="Permalink to &quot;Summary at the End&quot;">​</a></h2><p>After all files are processed, a summary notification tells you:</p><ul><li>How many files were <strong>imported</strong> successfully</li><li>How many were <strong>skipped</strong> (you chose to skip)</li><li>How many <strong>failed</strong> (the AI couldn&#39;t extract usable data)</li></ul><div class="tip custom-block"><p class="custom-block-title">Recommended order</p><p>If your PDFs cover different dates, getbased sorts data chronologically regardless of the import order. But importing oldest-to-newest can make it easier to review previews, since you&#39;ll see your history build up in order.</p></div><div class="warning custom-block"><p class="custom-block-title">Requires an AI provider</p><p>Each file in the batch goes through the same AI analysis as a single import. Make sure your AI provider is configured before starting a batch. See <a href="./ai-providers.html">AI Providers</a>.</p></div><h2 id="tips-for-large-batches" tabindex="-1">Tips for Large Batches <a class="header-anchor" href="#tips-for-large-batches" aria-label="Permalink to &quot;Tips for Large Batches&quot;">​</a></h2><ul><li>Start with a small batch (2–3 files) to make sure everything imports as expected before processing a decade of reports</li><li>Use JSON export to back up your data before a large batch import — see <a href="./json-export-import.html">JSON Export &amp; Import</a></li><li>If a file fails, you can always import it individually afterward</li></ul>',20)])])}const u=t(i,[["render",s]]);export{d as __pageData,u as default};
